                  <meshStandardMaterial 
                    color={status === 'EDITING' ? "#0f172a" : "#3f2e22"} 
                    roughness={0.9} 
                    metalness={0.1} 
                    transition="color 0.5s ease" 
                  />
                </mesh>

            </Canvas>
        </div>
    );
};

