import React, { useRef, useMemo, MutableRefObject, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { 
  Object3D, Color, Vector3, Group, InstancedMesh, Mesh, 
  SphereGeometry, CylinderGeometry, MeshStandardMaterial, MeshBasicMaterial 
} from 'three';
import { Organism, Node, Muscle } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  leaderRef: MutableRefObject<Organism | null>;
  showBestOnly: boolean;
  visionRadius: number;
  eatRadius: number; // NEW
}

// CACHED OBJECTS
const _tempObj = new Object3D();
const _color = new Color();
const _vecA = new Vector3();
const _vecB = new Vector3();
const _mid = new Vector3();

// COLORS
const COL_RED = new Color(0xff3333);
const COL_BLUE = new Color(0x3333ff);
const COL_WHITE = new Color(0xffffff);
const COL_YELLOW = new Color(0xffff00);
const COL_HEAD = new Color(0x1a1a1a);
const COL_DEAD = new Color(0x52525b);
const COL_GRIP = new Color(0x22c55e);

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, leaderRef, showBestOnly, visionRadius, eatRadius }) => {
  // 1. DEAD BODY REMOVAL: If dead, do not render anything.
  if (!organism.isAlive) return null;

  const groupRef = useRef<Group>(null);

  // Instanced Meshes
  const nodesMeshRef = useRef<InstancedMesh>(null);
  const musclesMeshRef = useRef<InstancedMesh>(null);

  // Singular items (Head indicators)
  const visionRef = useRef<Mesh>(null);
  const mouthRef = useRef<Mesh>(null);

  // Cache vector to store head position without allocations
  const headPosCache = useMemo(() => new Vector3(), []);

  // Geometries
  const nodeGeo = useMemo(() => new SphereGeometry(0.08, 6, 6), []); // Low Poly
  const muscleGeo = useMemo(() => new CylinderGeometry(0.03, 0.03, 1, 4), []); // Low Poly, Height=1 for easy scaling
  const visionGeo = useMemo(() => new SphereGeometry(1, 16, 16), []); 
  const mouthGeo = useMemo(() => new SphereGeometry(1, 16, 16), []); // Radius 1 base for easy scaling

  // Materials
  const nodeMat = useMemo(() => new MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const muscleMat = useMemo(() => new MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 }), []);
  const visionMat = useMemo(() => new MeshBasicMaterial({ 
      color: 0x00ffff, transparent: true, opacity: 0.05, wireframe: true 
  }), []);
  // Mouth Material (Pink to match slider)
  const mouthMat = useMemo(() => new MeshBasicMaterial({
      color: 0xec4899, transparent: true, opacity: 0.1, wireframe: true // pink-500
  }), []);

  // Set initial counts
  useEffect(() => {
      if (nodesMeshRef.current) nodesMeshRef.current.count = organism.nodes.length;
      if (musclesMeshRef.current) musclesMeshRef.current.count = organism.muscles.length;
  }, [organism.nodes.length, organism.muscles.length]);

  // Optimization: Pre-map node IDs to indices for fast lookup during muscle update
  const nodeIndexMap = useMemo(() => {
      const map = new Map<string, number>();
      organism.nodes.forEach((n, i) => map.set(n.id, i));
      return map;
  }, [organism.nodes]);


  useFrame((state) => {
    if (!groupRef.current) return;

    // Visibility Check
    if (showBestOnly) {
        const isLeader = leaderRef.current?.id === organism.id;
        groupRef.current.visible = isLeader;
    } else {
        groupRef.current.visible = true;
    }

    if (!groupRef.current.visible) return;

    let foundHead = false;
    // const isAlive = organism.isAlive; 
    // Note: isAlive is checked at the top of component, but we keep the logic generic below
    // in case we change the top check later.

    // --- UPDATE NODES ---
    if (nodesMeshRef.current) {
        for (let i = 0; i < organism.nodes.length; i++) {
            const node = organism.nodes[i];

            // Transform
            _tempObj.position.set(node.pos.x, node.pos.y, node.pos.z);
            _tempObj.scale.setScalar(1);
            _tempObj.rotation.set(0,0,0);
            _tempObj.updateMatrix();
            nodesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

            // Color
            if (node.isHead) {
                headPosCache.copy(_tempObj.position); // Store copy of position
                foundHead = true;
                nodesMeshRef.current.setColorAt(i, COL_HEAD);
            } else {
                const signal = node.gripSignal || 0;

                if (node.isGripping) {
                    // FULL GRIP: Solid Green
                    nodesMeshRef.current.setColorAt(i, COL_GRIP);
                } else {
                    // NORMAL: Activation glow
                    const act = node.activation || 0;
                    _color.copy(COL_WHITE).lerp(COL_YELLOW, act);

                    // INTENT OVERLAY: Brain wants to grip but can't (Air/Slip/Cooldown)
                    // Mix green into the base color based on how strong the signal is
                    if (signal > 0.1) {
                         _color.lerp(COL_GRIP, signal * 0.6); 
                    }

                    nodesMeshRef.current.setColorAt(i, _color);
                }
            }
        }
        nodesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (nodesMeshRef.current.instanceColor) nodesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE MUSCLES ---
    if (musclesMeshRef.current) {
        for (let i = 0; i < organism.muscles.length; i++) {
            const m = organism.muscles[i];
            // Lookup indices
            // We use direct array access if possible, but map is safer for partial updates
            const idxA = nodeIndexMap.get(m.nodeA);
            const idxB = nodeIndexMap.get(m.nodeB);

            if (idxA !== undefined && idxB !== undefined) {
                const nA = organism.nodes[idxA];
                const nB = organism.nodes[idxB];

                _vecA.set(nA.pos.x, nA.pos.y, nA.pos.z);
                _vecB.set(nB.pos.x, nB.pos.y, nB.pos.z);

                // Math to orient cylinder
                _mid.copy(_vecA).add(_vecB).multiplyScalar(0.5);
                const len = _vecA.distanceTo(_vecB);

                _tempObj.position.copy(_mid);
                _tempObj.lookAt(_vecB);
                _tempObj.rotateX(Math.PI / 2); // Align cylinder Y-axis to LookAt Z-axis
                _tempObj.scale.set(1, len, 1);
                _tempObj.updateMatrix();

                musclesMeshRef.current.setMatrixAt(i, _tempObj.matrix);

                // Color
                const target = m.targetLength || m.baseLength;
                const ratio = target / m.baseLength;
                if (ratio < 0.98) {
                    _color.copy(COL_WHITE).lerp(COL_RED, Math.min(1, (1 - ratio) * 5));
                } else if (ratio > 1.02) {
                    _color.copy(COL_WHITE).lerp(COL_BLUE, Math.min(1, (ratio - 1) * 5));
                } else {
                    _color.copy(COL_WHITE);
                }
                musclesMeshRef.current.setColorAt(i, _color);
            }
        }
        musclesMeshRef.current.instanceMatrix.needsUpdate = true;
        if (musclesMeshRef.current.instanceColor) musclesMeshRef.current.instanceColor.needsUpdate = true;
    }

    // --- UPDATE SINGULAR MESHES ---
    if (foundHead) {
        if (visionRef.current) {
            visionRef.current.position.copy(headPosCache);
            visionRef.current.scale.setScalar(visionRadius);
            visionRef.current.visible = true;
        }
        if (mouthRef.current) {
            mouthRef.current.position.copy(headPosCache);
            mouthRef.current.scale.setScalar(eatRadius); 
            mouthRef.current.visible = true;
        }
    } else {
        if (visionRef.current) visionRef.current.visible = false;
        if (mouthRef.current) mouthRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={visionRef} geometry={visionGeo} material={visionMat} />
      <mesh ref={mouthRef} geometry={mouthGeo} material={mouthMat} />

      {/* INSTANCED NODES */}
      <instancedMesh 
        ref={nodesMeshRef} 
        args={[nodeGeo, nodeMat, organism.nodes.length]}
        frustumCulled={false}
      />

      {/* INSTANCED MUSCLES */}
      <instancedMesh 
        ref={musclesMeshRef} 
        args={[muscleGeo, muscleMat, organism.muscles.length]}
        frustumCulled={false}
      />
    </group>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType, CellType, BlueprintCell } from '../../domain/types';
import { 
  Color, Matrix4, BoxGeometry, CylinderGeometry, Euler, Quaternion, 
  MeshStandardMaterial, InstancedMesh 
} from 'three';
import { EditorTool } from '../../App';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

// COLORS
const COL_BODY = new Color('#3b82f6'); // Blue
const COL_HEAD = new Color('#ef4444'); // Red
const COL_FOOT = new Color('#22c55e'); // Green

export const BlueprintView: React.FC<{
    cells: BlueprintCell[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
    brushType: CellType;
}> = ({ cells, onCellClick, currentType, editorTool, brushType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<InstancedMesh>(null);
  const tempMat = useMemo(() => new Matrix4(), []);

  const boxGeo = useMemo(() => new BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new CylinderGeometry(0.45, 0.45, 0.5, 6), []);
  const hexRotation = useMemo(() => new Euler(0, Math.PI/6, 0), []);
  const hexQuaternion = useMemo(() => new Quaternion().setFromEuler(hexRotation), []);

  // Materials
  const hoverMaterial = useMemo(() => new MeshStandardMaterial({ 
      color: '#ffffff', transparent: true, opacity: 0.6 
  }), []);
  const eraseMaterial = useMemo(() => new MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);

          // SET COLOR BASED ON CELL TYPE
          if (c.type === CellType.HEAD) meshRef.current!.setColorAt(i, COL_HEAD);
          else if (c.type === CellType.FOOT) meshRef.current!.setColorAt(i, COL_FOOT);
          else meshRef.current!.setColorAt(i, COL_BODY);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;
      if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;

      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat, hexQuaternion]);

  // Handle ghost color update
  useEffect(() => {
      if (editorTool === 'ERASE') return;
      if (brushType === CellType.HEAD) hoverMaterial.color.set(COL_HEAD);
      else if (brushType === CellType.FOOT) hoverMaterial.color.set(COL_FOOT);
      else hoverMaterial.color.set(COL_BODY);
  }, [brushType, hoverMaterial, editorTool]);

  // --- EVENTS ON MESH ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          const hitPoint = e.point;

          if (currentType === ShapeType.HEX) {
             const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const cy = c.y * hexHeight + (hexHeight/2);
             const relY = hitPoint.y - cy;

             if (relY > 0.23) { setHoverCoord({ x: c.x, y: c.y + 1, z: c.z }); return; }
             if (relY < -0.23) { setHoverCoord({ x: c.x, y: c.y - 1, z: c.z }); return; }

             let bestNeigh = null;
             let minD = Infinity;

             HEX_NEIGHBORS.forEach(n => {
                  const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                  const dx = pos.x - hitPoint.x;
                  const dz = pos.z - hitPoint.z;
                  const d = dx*dx + dz*dz;
                  if (d < minD) { minD = d; bestNeigh = n; }
             });

             if (bestNeigh) {
                 // @ts-ignore
                 setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
             }
          } else {
             if (e.face) {
                 const n = e.face.normal;
                 setHoverCoord({
                     x: c.x + Math.round(n.x),
                     y: c.y + Math.round(n.y),
                     z: c.z + Math.round(n.z)
                 });
             }
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true);
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null);
          return;
      }
      e.stopPropagation();

      const hitPoint = e.point;

      if (currentType === ShapeType.HEX) {
          const size = 0.6;
          const q = (2./3 * hitPoint.x) / size;
          const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

          let rx = Math.round(q);
          let rz = Math.round(r);
          let ry = Math.round(-q-r);

          const x_diff = Math.abs(rx - q);
          const y_diff = Math.abs(ry - (-q-r));
          const z_diff = Math.abs(rz - r);

          if (x_diff > y_diff && x_diff > z_diff) { rx = -ry-rz; } 
          else { rz = -rx-ry; }
          setHoverCoord({ x: rx, y: 0, z: rz });
      } else {
          setHoverCoord({
              x: Math.round(hitPoint.x),
              y: 0,
              z: Math.round(hitPoint.z)
          });
      }
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group onPointerMissed={handleMiss}>
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick}
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.45, 0.45, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          <meshStandardMaterial color="#ffffff" roughness={0.3} />
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                    pointerEvents="none" 
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                    pointerEvents="none" 
                 />
             )}
         </group>
      )}

      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[30, 30, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}
    </group>
  );
};

import React, { useRef, useMemo, MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import { Organism } from '../../domain/types';
import { 
  InstancedMesh, Object3D, Color, IcosahedronGeometry, MeshStandardMaterial 
} from 'three';

interface FoodViewProps {
    leaderRef: MutableRefObject<Organism | null>;
}

export const FoodView: React.FC<FoodViewProps> = ({ leaderRef }) => {
    const meshRef = useRef<InstancedMesh>(null);
    const tempObj = useMemo(() => new Object3D(), []);

    // COLORS
    const colDefault = useMemo(() => new Color('#22c55e'), []); // Green (Outside Vision)
    const colSeen = useMemo(() => new Color('#3b82f6'), []);    // Blue (Inside Vision)
    const colTarget = useMemo(() => new Color('#ec4899'), []);  // Pink (Locked Target)

    // Geometry/Material
    const geo = useMemo(() => new IcosahedronGeometry(0.15, 0), []);
    const mat = useMemo(() => new MeshStandardMaterial({ 
        color: '#ffffff', // Use white base for instance color
        emissive: '#ffffff',
        emissiveIntensity: 0.2,
        roughness: 0.2
    }), []);

    useFrame((state) => {
        if (!meshRef.current) return;

        // Use the centralized leader
        const leader = leaderRef.current;

        if (!leader || !leader.visibleFood) {
            meshRef.current.count = 0;
            return;
        }

        const foodItems = leader.visibleFood;
        meshRef.current.count = foodItems.length;

        // Use clock from state instead of Date.now()
        const time = state.clock.elapsedTime;

        // Update Instances
        for (let i = 0; i < foodItems.length; i++) {
            const item = foodItems[i];

            // Position
            tempObj.position.set(item.pos.x, item.pos.y, item.pos.z);

            // Animation: Spin
            tempObj.rotation.y += 0.02;
            tempObj.rotation.z += 0.01;

            // Scale: Shrink if consumed, else pulse
            if (item.consumed) {
                tempObj.scale.setScalar(0); 
            } else {
                const pulse = 1.0 + Math.sin(time * 3 + i) * 0.1;
                tempObj.scale.setScalar(pulse);
            }

            tempObj.updateMatrix();
            meshRef.current.setMatrixAt(i, tempObj.matrix);

            // COLOR LOGIC
            // If focused by brain, Pink. If seen, Blue. If hidden, Green.
            if (item.targeted) {
                meshRef.current.setColorAt(i, colTarget);
            } else if (item.seen) {
                meshRef.current.setColorAt(i, colSeen);
            } else {
                meshRef.current.setColorAt(i, colDefault);
            }
        }

        meshRef.current.instanceMatrix.needsUpdate = true;
        if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    });

    return (
        <instancedMesh 
            ref={meshRef} 
            args={[geo, mat, 100]} // Max 100 food items buffer
            frustumCulled={false}
        />
    );
};

import React, { useRef, MutableRefObject } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { Organism } from '../../domain/types';
import { CreatureView } from './CreatureView';
import { FoodView } from './FoodView';
import { Vector3 } from 'three';
// FIX: Use 'import type' to prevent bundling three-stdlib logic twice
import type { OrbitControls as OrbitControlsImpl } from 'three-stdlib';

interface SimulationLayerProps {
  population: Organism[];
  showBestOnly: boolean;
  visionRadius: number;
  eatRadius: number;
}

// COMPONENT: StableLeaderTracker
// Logic: Locks onto a leader and sticks with them to prevent camera jitter.
// Only switches if the leader dies or is overtaken by a significant margin (Hysteresis).
const StableLeaderTracker: React.FC<{ 
    population: Organism[], 
    leaderRef: MutableRefObject<Organism | null> 
}> = ({ population, leaderRef }) => {

    // Track the ID locally to detect death/switching
    const currentLeaderId = useRef<string | null>(null);

    useFrame(() => {
        if (!population.length) return;

        // 1. Find the current best candidate
        let bestCandidate: Organism | null = null;
        let bestZ = -Infinity;

        // Simple heuristic: furthest forward alive creature
        for (const org of population) {
            if (!org.isAlive) continue;

            // Calculate center Z
            let cz = 0;
            for(const n of org.nodes) cz += n.pos.z;
            cz /= org.nodes.length;

            if (cz > bestZ) {
                bestZ = cz;
                bestCandidate = org;
            }
        }

        // Fallback to best dead if everyone is dead
        if (!bestCandidate) {
             let bestDeadZ = -Infinity;
             for (const org of population) {
                let cz = 0;
                for(const n of org.nodes) cz += n.pos.z;
                cz /= org.nodes.length;
                if (cz > bestDeadZ) { bestDeadZ = cz; bestCandidate = org; }
             }
        }

        if (!bestCandidate) return;

        // 2. Stability Logic
        const current = leaderRef.current;

        // If we have no leader, or current leader is dead/gone, take the candidate
        if (!current || !current.isAlive || !population.find(o => o.id === current.id)) {
            leaderRef.current = bestCandidate;
            currentLeaderId.current = bestCandidate.id;
            return;
        }

        // If locked leader is still alive, check if we should switch
        // HYSTERESIS: Only switch if the candidate is significantly ahead (e.g., 2.0 units)
        // This prevents jitter when two creatures are neck-and-neck
        let currentZ = 0;
        for(const n of current.nodes) currentZ += n.pos.z;
        currentZ /= current.nodes.length;

        if (bestZ > currentZ + 4.0) {
            leaderRef.current = bestCandidate;
            currentLeaderId.current = bestCandidate.id;
        }
    });
    return null;
};

// COMPONENT: CameraDirector
const CameraDirector: React.FC<{ leaderRef: MutableRefObject<Organism | null> }> = ({ leaderRef }) => {
    const { camera } = useThree();
    const controlsRef = useRef<OrbitControlsImpl>(null);
    const targetRef = useRef(new Vector3(0, 0, 0));

    useFrame(() => {
        const leader = leaderRef.current;
        if (!leader) return;

        // Calculate Target Position
        let cx = 0, cy = 0, cz = 0;
        const len = leader.nodes.length;
        for (const n of leader.nodes) {
            cx += n.pos.x;
            cy += n.pos.y;
            cz += n.pos.z;
        }
        const center = new Vector3(cx/len, cy/len, cz/len);

        // Smoothly Interpolate Camera & Target
        // We use a slightly faster lerp for the target to keep the creature in frame during fast forward
        targetRef.current.lerp(center, 0.15);

        if (controlsRef.current) {
            const offset = camera.position.clone().sub(controlsRef.current.target);
            controlsRef.current.target.copy(targetRef.current);
            camera.position.copy(targetRef.current).add(offset);
            controlsRef.current.update();
        }
    });

    return (
        // @ts-ignore: maxPolarAngle exists on underlying OrbitControls but prop types might be strict
        <OrbitControls ref={controlsRef} makeDefault maxPolarAngle={Math.PI / 2 - 0.1} />
    );
};

export const SimulationLayer: React.FC<SimulationLayerProps> = ({ population, showBestOnly, visionRadius, eatRadius }) => {
  const leaderRef = useRef<Organism | null>(null);

  return (
    <group>
        <StableLeaderTracker population={population} leaderRef={leaderRef} />
        <CameraDirector leaderRef={leaderRef} />

        {population.map((org) => (
            <CreatureView 
              key={org.id} 
              organism={org} 
              leaderRef={leaderRef}
              showBestOnly={showBestOnly}
              visionRadius={visionRadius}
              eatRadius={eatRadius}
            />
        ))}

        <FoodView leaderRef={leaderRef} />
    </group>
  );
};

import React from 'react';
import { Canvas } from '@react-three/fiber';
import { Grid, PerspectiveCamera, OrbitControls } from '@react-three/drei';
import { SimulationLayer } from './SimulationLayer';
import { BlueprintView } from './BlueprintView';
import { Organism, ShapeType, CellType, BlueprintCell } from '../../domain/types';
import { EditorTool } from '../../App';

interface UnifiedStageProps {
    status: 'EDITING' | 'SIMULATING';
    // Sim Props
    population: Organism[];
    visionRadius: number;
    eatRadius?: number; // NEW
    showBestOnly: boolean;
    // Edit Props
    blueprintCells: BlueprintCell[];
    blueprintType: ShapeType;
    editorTool: EditorTool;
    brushType?: CellType;
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
}

export const UnifiedStage: React.FC<UnifiedStageProps> = ({
    status,
    population,
    visionRadius,
    eatRadius = 0.8, // Default
    showBestOnly,
    blueprintCells,
    blueprintType,
    editorTool,
    brushType,
    onCellClick
}) => {
    return (
        <div className={`w-full h-full bg-slate-900 ${status === 'EDITING' && editorTool !== 'VIEW' ? 'cursor-crosshair' : ''}`}>
            <Canvas shadows dpr={[1, 2]}>
                <PerspectiveCamera makeDefault position={[10, 8, 10]} fov={45} />
                <ambientLight intensity={0.6} />
                <directionalLight 
                  position={[20, 30, 10]} 
                  intensity={1.5} 
                  castShadow 
                  shadow-mapSize={[2048, 2048]} 
                />

                {status === 'SIMULATING' ? (
                    <SimulationLayer 
                        population={population}
                        showBestOnly={showBestOnly}
                        visionRadius={visionRadius}
                        eatRadius={eatRadius}
                    />
                ) : (
                    <>
                        <OrbitControls makeDefault target={[0, 0, 0]} />
                        <BlueprintView 
                             cells={blueprintCells}
                             onCellClick={onCellClick}
                             currentType={blueprintType}
                             editorTool={editorTool}
                             brushType={brushType || CellType.BODY}
                        />
                    </>
                )}

                {/* SHARED ENVIRONMENT */}
                <Grid 
                    position={[0, -0.01, 0]} 
                    args={[200, 200]} 
                    cellColor={status === 'EDITING' ? "#3b82f6" : "#5c4d3c"} 
                    sectionColor={status === 'EDITING' ? "#1e40af" : "#7f675b"} 
                    fadeDistance={60}
                    infiniteGrid
                />
                <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.05, 0]} receiveShadow>
                  <planeGeometry args={[1000, 1000]} />
                  <meshStandardMaterial 
                    color={status === 'EDITING' ? "#0f172a" : "#3f2e22"} 
                    roughness={0.9} 
                    metalness={0.1} 
                  />
                </mesh>

            </Canvas>
        </div>
    );
};

payload.text:
This is a classic problem in evolutionary physics simulations! You are describing the difference between **"Ice Skating"** (Viscous/Kinetic Friction) and **"Planting"** (Static Friction).

Currently, your physics engine applies a constant damping factor (0.7 friction) when on the ground. This means the moment a muscle pulls on a foot, the foot slides *a little bit*. When you sum that up over a whole stride, the creature spends more energy sliding its feet backward than pushing its body forward.

To fix this, we need to move the "Grip Logic" out of the **Brain** (Neural Network) and into the **Biomechanics** (Physics Engine). The brain shouldn't have to "think" about friction; the foot should just naturally grab the surface.

Here is the strategy to implement **Passive Static Friction**:

### 1. The "Stick vs. Slip" Threshold
Instead of always applying a friction multiplier (like `0.7`), we need a threshold.
*   **Concept:** If a FOOT node is on the ground, calculate how hard the muscles are pulling it horizontally.
*   **The Check:** If that pulling force is *below* a certain "Break Threshold," the foot **does not move at all**. It is anchored `(velocity = 0)`.
*   **The Slip:** Only if the muscles pull *harder* than the threshold does the foot "break loose" and start to slide.

### 2. Vertical Release (The "Lift" Mechanic)
This is the most important part for walking.
*   If the creature tries to push the foot *down* or pull it *sideways*, it sticks.
*   But, if the muscles generate a **Vertical Force** (trying to lift the leg), we reduce the friction to zero immediately.
*   **Why this helps:** The neural network effectively only needs to learn one thing: "Lift leg to step." It doesn't need to learn "Turn off suction, then lift leg." It lowers the cognitive load for evolution.

### 3. Directional Anisotropy (Optional but cool)
We can make feet like "ratchets" or snake scales.
*   High friction against the direction of movement (pushing back).
*   Low friction in the direction of movement (sliding forward).
*   *For now, I recommend sticking to #1 and #2, as they are more universal for legged walkers.*

### The Proposed Physics Logic

When we get to coding, we will change the `resolveFloor` function to look something like this pseudo-code:

```typescript
if (node.y <= 0 && node.type === CellType.FOOT) {
    // 1. Calculate how fast the node is trying to move this frame
    let velocityMag = node.getVelocity().length();

    // 2. Define a "Static Limit" (How sticky is the floor?)
    let staticLimit = 2.0; 

    // 3. The Logic
    if (velocityMag < staticLimit) {
        // ANCHOR: The force isn't strong enough to break the grip.
        // We force the position back to where it was.
        node.pos.x = node.oldPos.x;
        node.pos.z = node.oldPos.z;
        // Visuals: We can auto-set node.isGripping = true here for the UI
    } else {
        // SLIP: The creature is pulling too hard (or falling), so we apply drag
        applyFriction(0.6);
    }
}
```

### Why this changes everything
With this change, when a creature extends a rear leg, that rear foot will be "locked." The expansion of the muscle will force the **body mass forward** because the foot refuses to slide backward.

Currently, when a muscle expands, the body moves forward 50% and the foot slides backward 50%. This change will make it: Body moves forward 95%, foot slides 5%.

Shall I proceed with upgrading the `BioPhysicsEngine` to implement this **Static Friction Model** for `CellType.FOOT` nodes?

