import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism | null; // Nullable for disposal
  private isInitialized = false;

  // OPTIMIZATION: Flattened array for O(1) iteration
  private synapses: Synapse[] = []; 
  // OPTIMIZATION: Typed Array for weight access
  private synapseWeightsCache: Float32Array = new Float32Array(0);

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private muscleRestDistances: Float32Array;

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly HEBBIAN_RATE = 0.15; 

  // --- ATTENTION MECHANISM (Target Locking with Desire Decay) ---
  private currentTargetId: string | null = null;
  private currentAttention: number = 0.0; // 0.0 to 1.0 (Desire Level)

  // CONFIG: How long (in seconds) the creature stays 100% committed before doubt creeps in
  private readonly ATTENTION_SPAN = 6.0; 

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes
    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    // Init Empty Cache
    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  // NEW: Manual cleanup to help GC
  public dispose() {
      this.organism = null;
      this.neuralNodes.clear();
      this.synapses = [];
      // Explicitly detach large buffers
      this.synapseWeightsCache = new Float32Array(0);
      this.muscleRestDistances = new Float32Array(0);
      if (this.cpg) {
         // @ts-ignore: Force cleanup
         this.cpg.bufferA = null;
         // @ts-ignore
         this.cpg.bufferB = null;
      }
  }

  private initializeNervousSystem() {
      if (!this.organism || this.organism.nodes.length === 0) return;

      let headNode = this.organism.headNode;
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism!.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism!.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;
      this.synapseWeightsCache = new Float32Array(this.organism.neuralGenome.synapseWeights);

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodes.get(muscle.nodeA);
          const nnB = this.neuralNodes.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0, visionRadius: number = 4.0): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    const brainDt = dt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    // Update Attention Decay continuously (even between decision ticks)
    if (this.currentAttention > 0) {
        const decayPerSecond = 1.0 / this.ATTENTION_SPAN;
        this.currentAttention -= decayPerSecond * dt;
        if (this.currentAttention < 0) this.currentAttention = 0;
    }

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt, visionRadius);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;

    for(let i=0; i<this.organism.muscles.length; i++) {
        const m = this.organism.muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; 
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        m.targetLength = m.targetLength || m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number, visionRadius: number): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION
    let globalSensoryInput = 0;
    for (const nn of this.neuralNodes.values()) {
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION & DESIRE SYSTEM
    const head = this.organism.headNode;
    if (head) {
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        const vRadSq = visionRadius * visionRadius;

        // Reset DEBUG flags
        for(const food of this.organism.visibleFood) {
            food.seen = false;
            food.targeted = false;
        }

        // A. Validate Current Lock
        let lockedFood = null;
        let lockedRealDistSq = Infinity;

        if (this.currentTargetId) {
            const found = this.organism.visibleFood.find(f => f.id === this.currentTargetId);
            // Must check if it still exists and hasn't been eaten
            if (found && !found.consumed) {
                 const dx = found.pos.x - head.pos.x;
                 const dy = found.pos.y - head.pos.y;
                 const dz = found.pos.z - head.pos.z;
                 const dSq = dx*dx + dy*dy + dz*dz;

                 // Relaxed Vision Check: Once locked, we can track it slightly further than vision radius
                 // or even if it's slightly behind (memory).
                 // But for now, we enforce vision radius to avoid cheating.
                 if (dSq < vRadSq * 1.5) { // 1.5x buffer to prevent flickering at edge of vision
                     lockedFood = found;
                     lockedRealDistSq = dSq;
                 }
            }
        }

        // If we lost our target, reset attention immediately
        if (!lockedFood) {
            this.currentAttention = 0;
            this.currentTargetId = null;
        }

        // B. Calculate "Perceived Cost" of Current Target
        // Logic: Cost = Distance * (1 - Attention)
        // If Attention is 1.0 (100%), Cost is 0. No other food can beat it.
        // If Attention is 0.5, Cost is Half Distance.
        let currentPerceivedCost = Infinity;
        if (lockedFood) {
            // We use a high "Lock Strength" factor. 
            // 0.95 means even at 100% desire, it effectively shrinks distance by 95%.
            const lockFactor = this.currentAttention * 0.95;
            currentPerceivedCost = lockedRealDistSq * (1.0 - lockFactor);
        }

        // C. Evaluate Alternatives
        let bestCandidate = lockedFood;
        let bestCost = currentPerceivedCost;
        let switched = false;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;
            // Skip checking against itself
            if (lockedFood && food.id === lockedFood.id) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                food.seen = true;

                // New targets have no desire discount, so Cost = Actual Distance
                const cost = distSq;

                if (cost < bestCost) {
                    bestCost = cost;
                    bestCandidate = food;
                    switched = true;
                }
            }
        }

        // D. Apply Choice
        if (bestCandidate) {
            // Update Internal State
            if (switched) {
                this.currentTargetId = bestCandidate.id;
                // NEW LOVE: Reset Desire to 100%
                this.currentAttention = 1.0; 
            }

            bestCandidate.targeted = true; // Visualizer

            // --- NEURAL INPUT ---
            if (stability > 0.1) {
                const dist = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
                const dx = bestCandidate.pos.x - head.pos.x;
                const dy = bestCandidate.pos.y - head.pos.y;
                const dz = bestCandidate.pos.z - head.pos.z;

                const headNeural = this.neuralNodes.get(head.id);
                // NAN GUARD: Prevent division by zero if food spawns exactly on head
                if (headNeural && dist > 0.0001) {
                    const signalStrength = Math.max(0, 1.0 - (dist / visionRadius)) * stability;
                    // Normalized vector inputs
                    headNeural.inputSum += (dx / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dy / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dz / dist) * signalStrength * 3.0; 
                    globalSensoryInput += signalStrength * 2.0;
                }
            }
            this.previousDistanceToFood = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
        } else {
            this.previousDistanceToFood = Infinity;
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION
    for(let i=0; i<this.synapses.length; i++) {
        const s = this.synapses[i];
        const w = this.synapseWeightsCache[s.weightIndex]; 
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (const nn of this.neuralNodes.values()) {
        nn.updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism!.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5;

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism!.nodes;
        for(let i=0; i<nodes.length; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        }
    }
  }

  private learn(): void {
      if (!this.organism) return;
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      // 2. VESTIBULAR PAIN
      const head = this.organism.headNode;
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      // APPLY LEARNING (OPTIMIZED)
      if (Math.abs(learningSignal) > 0.1) {
          for(let i=0; i<this.synapses.length; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = this.synapseWeightsCache[s.weightIndex]; // Read from cache
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  // Clamp
                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  // Write to both for consistency
                  this.synapseWeightsCache[s.weightIndex] = w;
                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // Updated: Magnet defaults to same as eat radius for visual consistency
  public magnetRadius = 0.8; 
  private readonly MAGNET_FORCE = 0.8;  
  public eatRadius = 0.8;    

  public foodSpawnCount = 25; // REDUCED FROM 50 FOR PERFORMANCE
  public foodSpawnRadius = 3.5;

  // NEW: Dynamic Vision Radius
  public globalVisionRadius = 4.0;

  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).distanceWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set distanceWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get distanceWeight(): number { return (this.fitnessEvaluator as any).distanceWeight; }

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined; // Avoid circular ref or re-finding
          return value;
      });
      this.template = JSON.parse(safeJson);

      // Re-bind headNode if missing from JSON
      if (!this.template!.headNode) {
          this.template!.headNode = this.template!.nodes.find(n => n.isHead);
      }

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private cleanupCurrentPopulation() {
      // Explicitly break references to prevent leaks
      this.population.forEach(org => {
          if (org.brain && typeof org.brain.dispose === 'function') {
              org.brain.dispose();
          }
          org.brain = undefined;
      });
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.cleanupCurrentPopulation();

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      // OPTIMIZATION: Use cached headNode
      const head = organism.headNode;

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=0; i<sorted.length; i++) {
         // Everyone learns a little bit from the leader
         if (i === 0) continue;
         const learner = sorted[i];
         if (!learner.isAlive) continue;

         const learningRate = 0.01; 
         const lg = learner.neuralGenome;
         const bg = leader.neuralGenome;

         for(let k=0; k<lg.synapseWeights.length; k++) {
             if (bg.synapseWeights[k] !== undefined) {
                 lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
             }
         }
      }
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // 1. DEAD CHECK: Remove from calculations (Frozen Statue Logic)
      if (!org.isAlive) return;

      // 2. BRAIN UPDATE
      if (!org.brain) {
          org.brain = new BrainController(org);
      }
      const contractility = (this.engine as any).config.globalContractility;
      // Pass dynamic vision radius to brain
      org.brain.update(dt, contractility, this.globalVisionRadius);

      // 3. PHYSICS UPDATE
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          // OPTIMIZATION: Use Cached Head
          let head = org.headNode;

          // Self-heal just in case
          if (!head && org.nodes.length > 0) {
              head = org.nodes.find(n => n.isHead);
              if (!head) head = org.nodes[0];
              org.headNode = head;
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                // INLINED MATH (Optimized)
                // Avoid VectorOps.distance and VectorOps.sub object creation
                const dx = head.pos.x - food.pos.x;
                const dy = head.pos.y - food.pos.y;
                const dz = head.pos.z - food.pos.z;
                const distSq = dx*dx + dy*dy + dz*dz;

                // Fast reject check (Squared)
                // Use dynamic magnetRadius
                if (distSq < this.magnetRadius * this.magnetRadius) {
                    const dist = Math.sqrt(distSq);

                    // --- NAN GUARD: PREVENT MERGE SINGULARITY ---
                    // If food is sucked into the EXACT same coordinate as head (dist=0),
                    // the physics/vision vectors will become NaN (div by zero).
                    // We prevent this by gently nudging the food away if it gets too close.
                    if (dist < 0.0001) {
                         food.pos.x += 0.01; 
                         // Recalculate will happen next frame, preventing the NaN now.
                         continue;
                    }

                    // Pull Force
                    const strength = 1.0 - (dist / this.magnetRadius);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    // Apply directly (Pull vector is -diff vector)
                    // pull = head - food. so dx = head.x - food.x
                    food.pos.x += dx * force * 0.1;
                    food.pos.y += dy * force * 0.1;
                    food.pos.z += dz * force * 0.1;

                    // Recheck Distance (Cheap approximation: assume it moved closer)
                    const ndx = head.pos.x - food.pos.x;
                    const ndy = head.pos.y - food.pos.y;
                    const ndz = head.pos.z - food.pos.z;
                    const nDistSq = ndx*ndx + ndy*ndy + ndz*ndz;

                    // Use dynamic eatRadius
                    if (nDistSq < this.eatRadius * this.eatRadius) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    // Cleanup Old Population before switching
    this.cleanupCurrentPopulation();

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, 
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2,
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome 
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          // Distance Stats
          initialHeadPos: template.initialHeadPos ? { ...template.initialHeadPos } : {x:0,y:0,z:0},
          distanceTraveled: 0
      };

      // Safety check for starting pos if template was malformed
      if (!clone.initialHeadPos) {
           const head = clone.nodes.find(n => n.isHead);
           clone.initialHeadPos = head ? { ...head.pos } : { x: 0, y: 0, z: 0 };
      }

      // OPTIMIZATION: Cache Head
      const head = clone.nodes.find(n => n.isHead);
      if (head) clone.headNode = head;

      return clone;
  }

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

import { Node, Muscle, Organism, SimulationConfig, CellType } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS (Optimized)
  private readonly RELAXATION_FACTOR = 0.8; // Higher relaxation for fewer steps
  private readonly ITERATIONS = 3; // Reduced from 6 for performance

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  // --- GRIP CONSTANTS (Reflexive System) ---
  private readonly GRIP_DRAIN_RATE = 2.5; 
  private readonly GRIP_RECHARGE_RATE = 0.05; 
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; // Force needed to break grip

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, 
      groundDamping: 0.8, 
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, 
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. PHYSICS INTEGRATION

    // Handle Ragdoll state
    if (!organism.isAlive) {
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
        // Release all grips if dead
        organism.nodes.forEach(n => {
            n.isGripping = false;
        });
    }

    // ADAPTIVE SUBSTEPS (Optimized)
    const subSteps = fastMode ? 3 : 8; // Reduced from 4/12
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        // Stop processing immediately if organism died in previous substep
        if (!organism.isAlive && s > 0) break;

        // RESET STRESS for this step (it accumulates during muscle resolution)
        for(let i=0; i<organism.nodes.length; i++) {
            organism.nodes[i].currentStress = 0;
        }

        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        const loops = fastMode ? 2 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // OPTIMIZATION: Only resolve self-collisions on the last iteration
            // This cuts the most expensive operation by 66%
            if (!fastMode && i === loops - 1) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);

        // --- NAN GUARD (Per Substep) ---
        // We check every substep. If a calculation explodes, we stop immediately.
        // This prevents "NaN" from propagating and filling the logs.
        let exploded = false;
        for(let n of organism.nodes) {
            if (isNaN(n.pos.x) || isNaN(n.pos.y) || isNaN(n.pos.z)) {
                exploded = true;
                break;
            }
        }

        if (exploded) {
             console.warn(`Organism ${organism.id} exploded (NaN detected). Killing.`);
             organism.isAlive = false;
             organism.energy = 0;
             // Reset to safe zero to prevent render crash and break loop
             for(let n of organism.nodes) {
                 n.pos = { x: 0, y: 0, z: 0 };
                 n.oldPos = { x: 0, y: 0, z: 0 };
             }
             break; // EXIT SUBSTEPS
        }
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      if (isNaN(angularVel)) return; // Guard

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      // AUTO-GRIP MECHANIC: FREEZE MOMENTUM IF GRIPPING
      if (node.isGripping) {
          node.oldPos.x = node.pos.x;
          node.oldPos.z = node.pos.z;
      }

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq && distSq > 0) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const ANCHOR_MULTIPLIER = 0.001; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;
        if (distSq < 0.0000001) continue; 

        const dist = Math.sqrt(distSq);

        // 1. ACTIVE MUSCLE COMPONENT
        // INPUT SANITIZATION: Brain might send NaN target lengths
        let activeTarget = muscle.targetLength;
        if (activeTarget === undefined || isNaN(activeTarget)) {
            activeTarget = muscle.baseLength;
        }

        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        // Inline vector math for speed
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        // Dot product projection
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        // Simplified dynamic damping
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (Math.abs(vRelProj) * this.ADAPTIVE_DAMPING_FACTOR);

        totalCorrection += vRelProj * dynamicDamping;

        // --- STRESS ACCUMULATION ---
        const stress = Math.abs(totalCorrection);
        n1.currentStress = (n1.currentStress || 0) + stress;
        n2.currentStress = (n2.currentStress || 0) + stress;

        // --- MOMENTUM PRESERVATION ---
        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.isGripping) im1 *= ANCHOR_MULTIPLIER;
        if (n2.isGripping) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      // O(N^2) check - Expensive! 
      // Optimized by only running on final iteration
      for (let i = 0; i < count; i++) {
          const n1 = nodes[i];
          for (let j = i + 1; j < count; j++) {
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const KINETIC_FRICTION = 0.6; // Slipping friction

    for (const node of organism.nodes) {
      if (node.gripStamina === undefined) node.gripStamina = 1.0;
      if (node.gripCooldown === undefined) node.gripCooldown = 0; 

      if (node.gripCooldown > 0) node.gripCooldown--;

      if (node.pos.y < RADIUS) {
        node.pos.y = RADIUS;

        if (node.isHead) {
            organism.isAlive = false;
            organism.energy = 0;
        }

        // --- NEW STATIC FRICTION MODEL ---
        // A node is a "foot" if specifically designated OR if it has high friction (Legacy support)
        const isFoot = node.cellType === CellType.FOOT || (node.friction > 0.8 && !node.isHead);

        // Brain Override: Creature can manually clutch if it wants
        const brainWantsGrip = (node.gripSignal || 0) > 0.5;
        const canGrip = node.gripStamina > 0 && node.gripCooldown <= 0;
        const manualGrip = brainWantsGrip && canGrip;

        if (isFoot || manualGrip) {
            // Calculate attempted motion (Velocity)
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const vSq = vx*vx + vz*vz;

            // If manual grip, infinite threshold. If passive foot, use configured static limit.
            // Ensure thresholdSq is a valid number, even if calculations drift
            const thresholdSq = manualGrip ? Infinity : (this.STATIC_FRICTION_THRESHOLD * this.STATIC_FRICTION_THRESHOLD);

            // NAN GUARD: If vSq is invalid, reset logic
            if (isNaN(vSq)) {
                node.isGripping = false;
                continue;
            }

            if (vSq < thresholdSq) {
                // STICK (Static Friction)
                // Kill horizontal momentum completely to simulate "planting"
                node.oldPos.x = node.pos.x;
                node.oldPos.z = node.pos.z;

                node.isGripping = true; // Visual Feedback

                // If manual grip, it drains energy
                if (manualGrip) {
                    const stress = node.currentStress || 0;
                    const drain = 0.005 + (stress * this.GRIP_DRAIN_RATE);
                    node.gripStamina -= drain;
                    if (node.gripStamina <= 0) {
                        node.gripStamina = 0;
                        node.gripCooldown = 15;
                    }
                }
            } else {
                // SLIP (Kinetic Friction)
                // Force exceeded grip strength, so it slides
                node.isGripping = false;
                const friction = KINETIC_FRICTION;
                node.oldPos.x = node.pos.x - vx * friction;
                node.oldPos.z = node.pos.z - vz * friction;
            }
        } else {
            // SLIP (Standard Low Friction Body)
            node.isGripping = false;
            // Use the node's natural friction if defined, else slippery default
            const friction = node.friction || 0.5; 
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            node.oldPos.x = node.pos.x - vx * friction;
            node.oldPos.z = node.pos.z - vz * friction;
        }

      } else {
          // AIR
          node.isGripping = false;
          node.gripStamina += this.GRIP_RECHARGE_RATE;
          if (node.gripStamina > 1.0) node.gripStamina = 1.0;
      }
    }
  }
}

import { Node, Muscle, Organism, SimulationConfig, CellType } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; 

  // SOLVER SETTINGS (Optimized)
  private readonly RELAXATION_FACTOR = 0.8; // Higher relaxation for fewer steps
  private readonly ITERATIONS = 3; // Reduced from 6 for performance

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  // --- GRIP CONSTANTS (Reflexive System) ---
  private readonly GRIP_DRAIN_RATE = 2.5; 
  private readonly GRIP_RECHARGE_RATE = 0.05; 
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; // Force needed to break grip

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, 
      groundDamping: 0.5, // Energy lost on impact (0.5 = 50% retained)
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, 
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 0. PRE-FLIGHT CHECK
    // If the organism is already corrupted, do not attempt to solve.
    if (!organism.isAlive) return; // Skip dead
    for(const n of organism.nodes) {
        if (isNaN(n.pos.x)) {
            organism.isAlive = false;
            return;
        }
    }

    // 1. PHYSICS INTEGRATION

    // ADAPTIVE SUBSTEPS (Optimized)
    const subSteps = fastMode ? 3 : 8; // Reduced from 4/12
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        // Stop processing immediately if organism died in previous substep
        if (!organism.isAlive && s > 0) break;

        // RESET STRESS for this step (it accumulates during muscle resolution)
        for(let i=0; i<organism.nodes.length; i++) {
            organism.nodes[i].currentStress = 0;
        }

        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        const loops = fastMode ? 2 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // OPTIMIZATION: Only resolve self-collisions on the last iteration
            // This cuts the most expensive operation by 66%
            if (!fastMode && i === loops - 1) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);

        // --- NAN GUARD (Per Substep) ---
        // We check every substep. If a calculation explodes, we stop immediately.
        let exploded = false;
        for(let n of organism.nodes) {
            if (isNaN(n.pos.x) || isNaN(n.pos.y) || isNaN(n.pos.z)) {
                exploded = true;
                break;
            }
        }

        if (exploded) {
             console.warn(`Organism ${organism.id} exploded (NaN detected). Killing.`);
             organism.isAlive = false;
             organism.energy = 0;
             // Reset to safe zero to prevent render crash and break loop
             for(let n of organism.nodes) {
                 n.pos = { x: 0, y: 0, z: 0 };
                 n.oldPos = { x: 0, y: 0, z: 0 };
             }
             break; // EXIT SUBSTEPS
        }
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      if (isNaN(angularVel)) return; // Guard

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      // AUTO-GRIP MECHANIC: FREEZE MOMENTUM IF GRIPPING
      if (node.isGripping) {
          node.oldPos.x = node.pos.x;
          node.oldPos.z = node.pos.z;
      }

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction (Air)
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq && distSq > 0) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      // GC OPTIMIZATION: Update oldPos in place instead of creating new object
      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const ANCHOR_MULTIPLIER = 0.001; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // CACHE REFERENCES (Lazy Load)
    if (!organism.muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (const m of organism.muscles) {
             m.nodeRefA = nodeMap.get(m.nodeA);
             m.nodeRefB = nodeMap.get(m.nodeB);
         }
    }

    for (const muscle of organism.muscles) {
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;
        if (distSq < 0.0000001) continue; 

        const dist = Math.sqrt(distSq);

        // 1. ACTIVE MUSCLE COMPONENT
        // INPUT SANITIZATION: Brain might send NaN target lengths
        let activeTarget = muscle.targetLength;
        if (activeTarget === undefined || isNaN(activeTarget)) {
            activeTarget = muscle.baseLength;
        }

        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;
        const strainBoost = 1.0 + (strain * 4.0); 

        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // --- DAMPING ---
        // Inline vector math for speed
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        // Dot product projection
        const vRelProj = rvx * nx + rvy * ny + rvz * nz;

        // Simplified dynamic damping
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (Math.abs(vRelProj) * this.ADAPTIVE_DAMPING_FACTOR);

        totalCorrection += vRelProj * dynamicDamping;

        // --- STRESS ACCUMULATION ---
        const stress = Math.abs(totalCorrection);
        n1.currentStress = (n1.currentStress || 0) + stress;
        n2.currentStress = (n2.currentStress || 0) + stress;

        // --- MOMENTUM PRESERVATION ---
        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.isGripping) im1 *= ANCHOR_MULTIPLIER;
        if (n2.isGripping) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      // O(N^2) check - Expensive! 
      // Optimized by only running on final iteration
      for (let i = 0; i < count; i++) {
          const n1 = nodes[i];
          for (let j = i + 1; j < count; j++) {
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  const fx = (dx / dist) * overlap * 0.2;
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const KINETIC_FRICTION = 0.6; // Slipping friction

    for (const node of organism.nodes) {
      if (node.gripStamina === undefined) node.gripStamina = 1.0;
      if (node.gripCooldown === undefined) node.gripCooldown = 0; 

      if (node.gripCooldown > 0) node.gripCooldown--;

      if (node.pos.y < RADIUS) {
        // ENERGY PRESERVATION:
        // When hitting floor, we must dampen the vertical energy or it will bounce forever/explode.
        const dy = node.pos.y - node.oldPos.y;

        node.pos.y = RADIUS;

        // Apply Impact Damping (Reflect velocity with loss)
        if (dy < 0) {
             node.oldPos.y = node.pos.y + dy * this.config.groundDamping;
        }

        if (node.isHead) {
            organism.isAlive = false;
            organism.energy = 0;
        }

        // --- NEW STATIC FRICTION MODEL ---
        // A node is a "foot" if specifically designated OR if it has high friction (Legacy support)
        const isFoot = node.cellType === CellType.FOOT || (node.friction > 0.8 && !node.isHead);

        // Brain Override: Creature can manually clutch if it wants
        const brainWantsGrip = (node.gripSignal || 0) > 0.5;
        const canGrip = node.gripStamina > 0 && node.gripCooldown <= 0;
        const manualGrip = brainWantsGrip && canGrip;

        if (isFoot || manualGrip) {
            // Calculate attempted motion (Velocity)
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const vSq = vx*vx + vz*vz;

            // If manual grip, infinite threshold. If passive foot, use configured static limit.
            // Ensure thresholdSq is a valid number, even if calculations drift
            const thresholdSq = manualGrip ? Infinity : (this.STATIC_FRICTION_THRESHOLD * this.STATIC_FRICTION_THRESHOLD);

            // NAN GUARD: If vSq is invalid, reset logic
            if (isNaN(vSq)) {
                node.isGripping = false;
                continue;
            }

            if (vSq < thresholdSq) {
                // STICK (Static Friction)
                // Kill horizontal momentum completely to simulate "planting"
                node.oldPos.x = node.pos.x;
                node.oldPos.z = node.pos.z;

                node.isGripping = true; // Visual Feedback

                // If manual grip, it drains energy
                if (manualGrip) {
                    const stress = node.currentStress || 0;
                    const drain = 0.005 + (stress * this.GRIP_DRAIN_RATE);
                    node.gripStamina -= drain;
                    if (node.gripStamina <= 0) {
                        node.gripStamina = 0;
                        node.gripCooldown = 15;
                    }
                }
            } else {
                // SLIP (Kinetic Friction)
                // Force exceeded grip strength, so it slides
                node.isGripping = false;
                const friction = KINETIC_FRICTION;
                node.oldPos.x = node.pos.x - vx * friction;
                node.oldPos.z = node.pos.z - vz * friction;
            }
        } else {
            // SLIP (Standard Low Friction Body)
            node.isGripping = false;
            // Use the node's natural friction if defined, else slippery default
            const friction = node.friction || 0.5; 
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            node.oldPos.x = node.pos.x - vx * friction;
            node.oldPos.z = node.pos.z - vz * friction;
        }

      } else {
          // AIR
          node.isGripping = false;
          node.gripStamina += this.GRIP_RECHARGE_RATE;
          if (node.gripStamina > 1.0) node.gripStamina = 1.0;
      }
    }
  }
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism | null; // Nullable for disposal
  private isInitialized = false;

  // OPTIMIZATION: Flattened array for O(1) iteration
  private synapses: Synapse[] = []; 
  // OPTIMIZATION: Typed Array for weight access
  private synapseWeightsCache: Float32Array = new Float32Array(0);

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private muscleRestDistances: Float32Array;

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly HEBBIAN_RATE = 0.15; 

  // --- ATTENTION MECHANISM (Target Locking with Desire Decay) ---
  private currentTargetId: string | null = null;
  private currentAttention: number = 0.0; // 0.0 to 1.0 (Desire Level)

  // CONFIG: How long (in seconds) the creature stays 100% committed before doubt creeps in
  private readonly ATTENTION_SPAN = 6.0; 

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes
    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    // Init Empty Cache
    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  // NEW: Manual cleanup to help GC
  public dispose() {
      this.organism = null;
      this.neuralNodes.clear();
      this.synapses = [];
      // Explicitly detach large buffers
      this.synapseWeightsCache = new Float32Array(0);
      this.muscleRestDistances = new Float32Array(0);
      if (this.cpg) {
         // @ts-ignore: Force cleanup
         this.cpg.bufferA = null;
         // @ts-ignore
         this.cpg.bufferB = null;
      }
  }

  private initializeNervousSystem() {
      if (!this.organism || this.organism.nodes.length === 0) return;

      let headNode = this.organism.headNode;
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism!.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism!.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;
      this.synapseWeightsCache = new Float32Array(this.organism.neuralGenome.synapseWeights);

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodes.get(muscle.nodeA);
          const nnB = this.neuralNodes.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0, visionRadius: number = 4.0): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    // Safety: Cap dt to prevent brain explosion on lag spike
    const safeDt = Math.min(dt, 0.1); 
    const brainDt = safeDt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    // Update Attention Decay continuously (even between decision ticks)
    if (this.currentAttention > 0) {
        const decayPerSecond = 1.0 / this.ATTENTION_SPAN;
        this.currentAttention -= decayPerSecond * safeDt;
        if (this.currentAttention < 0) this.currentAttention = 0;
    }

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt, visionRadius);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;

    for(let i=0; i<this.organism.muscles.length; i++) {
        const m = this.organism.muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; 
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // Safety Clamp
        if (isNaN(totalSignal)) totalSignal = 0;
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        m.targetLength = m.targetLength || m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number, visionRadius: number): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION
    let globalSensoryInput = 0;
    for (const nn of this.neuralNodes.values()) {
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION & DESIRE SYSTEM
    const head = this.organism.headNode;
    if (head) {
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        const vRadSq = visionRadius * visionRadius;

        // Reset DEBUG flags
        for(const food of this.organism.visibleFood) {
            food.seen = false;
            food.targeted = false;
        }

        // A. Validate Current Lock
        let lockedFood = null;
        let lockedRealDistSq = Infinity;

        if (this.currentTargetId) {
            const found = this.organism.visibleFood.find(f => f.id === this.currentTargetId);
            // Must check if it still exists and hasn't been eaten
            if (found && !found.consumed) {
                 const dx = found.pos.x - head.pos.x;
                 const dy = found.pos.y - head.pos.y;
                 const dz = found.pos.z - head.pos.z;
                 const dSq = dx*dx + dy*dy + dz*dz;

                 // Relaxed Vision Check: Once locked, we can track it slightly further than vision radius
                 // or even if it's slightly behind (memory).
                 // But for now, we enforce vision radius to avoid cheating.
                 if (dSq < vRadSq * 1.5) { // 1.5x buffer to prevent flickering at edge of vision
                     lockedFood = found;
                     lockedRealDistSq = dSq;
                 }
            }
        }

        // If we lost our target, reset attention immediately
        if (!lockedFood) {
            this.currentAttention = 0;
            this.currentTargetId = null;
        }

        // B. Calculate "Perceived Cost" of Current Target
        // Logic: Cost = Distance * (1 - Attention)
        // If Attention is 1.0 (100%), Cost is 0. No other food can beat it.
        // If Attention is 0.5, Cost is Half Distance.
        let currentPerceivedCost = Infinity;
        if (lockedFood) {
            // We use a high "Lock Strength" factor. 
            // 0.95 means even at 100% desire, it effectively shrinks distance by 95%.
            const lockFactor = this.currentAttention * 0.95;
            currentPerceivedCost = lockedRealDistSq * (1.0 - lockFactor);
        }

        // C. Evaluate Alternatives
        let bestCandidate = lockedFood;
        let bestCost = currentPerceivedCost;
        let switched = false;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;
            // Skip checking against itself
            if (lockedFood && food.id === lockedFood.id) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                food.seen = true;

                // New targets have no desire discount, so Cost = Actual Distance
                const cost = distSq;

                if (cost < bestCost) {
                    bestCost = cost;
                    bestCandidate = food;
                    switched = true;
                }
            }
        }

        // D. Apply Choice
        if (bestCandidate) {
            // Update Internal State
            if (switched) {
                this.currentTargetId = bestCandidate.id;
                // NEW LOVE: Reset Desire to 100%
                this.currentAttention = 1.0; 
            }

            bestCandidate.targeted = true; // Visualizer

            // --- NEURAL INPUT ---
            if (stability > 0.1) {
                const dist = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
                const dx = bestCandidate.pos.x - head.pos.x;
                const dy = bestCandidate.pos.y - head.pos.y;
                const dz = bestCandidate.pos.z - head.pos.z;

                const headNeural = this.neuralNodes.get(head.id);
                // NAN GUARD: Prevent division by zero if food spawns exactly on head
                if (headNeural && dist > 0.0001) {
                    const signalStrength = Math.max(0, 1.0 - (dist / visionRadius)) * stability;
                    // Normalized vector inputs
                    headNeural.inputSum += (dx / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dy / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dz / dist) * signalStrength * 3.0; 
                    globalSensoryInput += signalStrength * 2.0;
                }
            }
            this.previousDistanceToFood = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
        } else {
            this.previousDistanceToFood = Infinity;
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);
    if (isNaN(globalSensoryInput)) globalSensoryInput = 0; // Guard

    // 3. SYNAPTIC PROPAGATION
    for(let i=0; i<this.synapses.length; i++) {
        const s = this.synapses[i];
        const w = this.synapseWeightsCache[s.weightIndex]; 
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (const nn of this.neuralNodes.values()) {
        nn.updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism!.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        // Output Clamping
        const targetAmp = Math.min(1.0, Math.abs(rawAmp)) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5;

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;

        if (isNaN(muscle.amp)) muscle.amp = 0;
        if (isNaN(muscle.freq)) muscle.freq = 1.0;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism!.nodes;
        for(let i=0; i<nodes.length; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;

            if (isNaN(node.gripSignal)) node.gripSignal = 0;
        }
    }
  }

  private learn(): void {
      if (!this.organism) return;
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      // 1. METABOLIC REWARD
      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      // 2. VESTIBULAR PAIN
      const head = this.organism.headNode;
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      // APPLY LEARNING (OPTIMIZED)
      if (Math.abs(learningSignal) > 0.1) {
          for(let i=0; i<this.synapses.length; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = this.synapseWeightsCache[s.weightIndex]; // Read from cache
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  // Clamp
                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  // Write to both for consistency
                  this.synapseWeightsCache[s.weightIndex] = w;
                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType, CellType, BlueprintCell } from '../../domain/types';
import { 
  Color, Matrix4, BoxGeometry, CylinderGeometry, Euler, Quaternion, 
  MeshStandardMaterial, InstancedMesh, LineSegments, EdgesGeometry, BufferGeometry, Float32BufferAttribute 
} from 'three';
import { EditorTool } from '../../App';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

// COLORS
const COL_BODY = new Color('#3b82f6'); // Blue
const COL_HEAD = new Color('#ef4444'); // Red
const COL_FOOT = new Color('#22c55e'); // Green

// --- CUSTOM HEX GRID HELPER ---
const HexGridHelper: React.FC = () => {
    const radius = 15; // Grid radius in hexes
    const size = 0.6; // Visual scale matches logic

    const geometry = useMemo(() => {
        const vertices: number[] = [];

        // Generate hex lines
        for (let q = -radius; q <= radius; q++) {
            for (let r = -radius; r <= radius; r++) {
                if (Math.abs(q + r) > radius) continue; // Keep it vaguely circular

                const { x: cx, z: cz } = hexToPixel(q, r, size);

                // Calculate 6 corners of this hex
                for (let i = 0; i < 6; i++) {
                    const angle = (Math.PI / 3) * i;
                    const angleNext = (Math.PI / 3) * (i + 1);

                    // We draw individual line segments for "honeycomb" look
                    // Optimization: This draws duplicate lines on shared edges, but is simpler than edge-deduplication for a helper.
                    const x1 = cx + size * Math.cos(angle);
                    const z1 = cz + size * Math.sin(angle);

                    const x2 = cx + size * Math.cos(angleNext);
                    const z2 = cz + size * Math.sin(angleNext);

                    vertices.push(x1, 0, z1);
                    vertices.push(x2, 0, z2);
                }
            }
        }

        const geo = new BufferGeometry();
        geo.setAttribute('position', new Float32BufferAttribute(vertices, 3));
        return geo;
    }, []);

    return (
        <lineSegments position={[0, -0.48, 0]} geometry={geometry}>
            <lineBasicMaterial color="#444444" opacity={0.5} transparent />
        </lineSegments>
    );
};

export const BlueprintView: React.FC<{
    cells: BlueprintCell[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
    brushType: CellType;
}> = ({ cells, onCellClick, currentType, editorTool, brushType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<InstancedMesh>(null);
  const tempMat = useMemo(() => new Matrix4(), []);

  const boxGeo = useMemo(() => new BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new CylinderGeometry(0.5, 0.5, 0.5, 6), []); // Slightly larger to fill gaps
  const hexRotation = useMemo(() => new Euler(0, Math.PI/6, 0), []); // Pointy top alignment
  const hexQuaternion = useMemo(() => new Quaternion().setFromEuler(hexRotation), []);

  // Materials
  const hoverMaterial = useMemo(() => new MeshStandardMaterial({ 
      color: '#ffffff', transparent: true, opacity: 0.6 
  }), []);
  const eraseMaterial = useMemo(() => new MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          if (currentType === ShapeType.HEX) {
             const {x, z} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const yPos = c.y * hexHeight + (hexHeight/2);
             tempMat.makeRotationFromQuaternion(hexQuaternion);
             tempMat.setPosition(x, yPos, z);
          } else {
             tempMat.setPosition(c.x, c.y, c.z);
          }
          meshRef.current!.setMatrixAt(i, tempMat);

          // SET COLOR BASED ON CELL TYPE
          if (c.type === CellType.HEAD) meshRef.current!.setColorAt(i, COL_HEAD);
          else if (c.type === CellType.FOOT) meshRef.current!.setColorAt(i, COL_FOOT);
          else meshRef.current!.setColorAt(i, COL_BODY);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;
      if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;

      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat, hexQuaternion]);

  // Handle ghost color update
  useEffect(() => {
      if (editorTool === 'ERASE') return;
      if (brushType === CellType.HEAD) hoverMaterial.color.set(COL_HEAD);
      else if (brushType === CellType.FOOT) hoverMaterial.color.set(COL_FOOT);
      else hoverMaterial.color.set(COL_BODY);
  }, [brushType, hoverMaterial, editorTool]);

  // --- EVENTS ON MESH ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
          const hitPoint = e.point;

          if (currentType === ShapeType.HEX) {
             const {x: cx, z: cz} = hexToPixel(c.x, c.z, 0.6);
             const hexHeight = 0.5;
             const cy = c.y * hexHeight + (hexHeight/2);
             const relY = hitPoint.y - cy;

             // Vertical stacking logic
             if (relY > 0.23) { setHoverCoord({ x: c.x, y: c.y + 1, z: c.z }); return; }
             if (relY < -0.23) { setHoverCoord({ x: c.x, y: c.y - 1, z: c.z }); return; }

             let bestNeigh = null;
             let minD = Infinity;

             HEX_NEIGHBORS.forEach(n => {
                  const pos = hexToPixel(c.x + n.q, c.z + n.r, 0.6);
                  const dx = pos.x - hitPoint.x;
                  const dz = pos.z - hitPoint.z;
                  const d = dx*dx + dz*dz;
                  if (d < minD) { minD = d; bestNeigh = n; }
             });

             if (bestNeigh) {
                 // @ts-ignore
                 setHoverCoord({ x: c.x + bestNeigh.q, y: c.y, z: c.z + bestNeigh.r });
             }
          } else {
             if (e.face) {
                 const n = e.face.normal;
                 setHoverCoord({
                     x: c.x + Math.round(n.x),
                     y: c.y + Math.round(n.y),
                     z: c.z + Math.round(n.z)
                 });
             }
          }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true);
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null);
          return;
      }
      e.stopPropagation();

      const hitPoint = e.point;

      if (currentType === ShapeType.HEX) {
          const size = 0.6;
          // Math for converting world coords to axial hex coords
          const q = (2./3 * hitPoint.x) / size;
          const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

          let rx = Math.round(q);
          let rz = Math.round(r);
          let ry = Math.round(-q-r);

          const x_diff = Math.abs(rx - q);
          const y_diff = Math.abs(ry - (-q-r));
          const z_diff = Math.abs(rz - r);

          if (x_diff > y_diff && x_diff > z_diff) { rx = -ry-rz; } 
          else { rz = -rx-ry; }
          setHoverCoord({ x: rx, y: 0, z: rz });
      } else {
          setHoverCoord({
              x: Math.round(hitPoint.x),
              y: 0,
              z: Math.round(hitPoint.z)
          });
      }
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group onPointerMissed={handleMiss}>
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick}
      >
          {currentType === ShapeType.HEX 
            ? <cylinderGeometry args={[0.5, 0.5, 0.5, 6]} /> 
            : <boxGeometry args={[0.8, 0.8, 0.8]} />
          }
          <meshStandardMaterial color="#ffffff" roughness={0.3} />
      </instancedMesh>

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                    pointerEvents="none" 
                 />
             ) : (
                 <mesh 
                    position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                    geometry={boxGeo} 
                    material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                    pointerEvents="none" 
                 />
             )}
         </group>
      )}

      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.5, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[60, 60]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <HexGridHelper />
      ) : (
           <gridHelper args={[30, 30, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}
    </group>
  );
};

